"use client";

import { ark } from "@ark-ui/react";
import { Drawer as ArkDrawer } from "@ark-ui/react/drawer";
import { Portal } from "@ark-ui/react/portal";
import { XIcon } from "lucide-react";
import type React from "react";
import { tv, type VariantProps } from "tailwind-variants";
import { cn } from "@/lib/utils";
import { Button } from "@/registry/react/components/button";
import { ScrollArea } from "@/registry/react/components/scroll-area";

export type SwipeDirection = "up" | "down" | "left" | "right";

export const Drawer = (props: React.ComponentProps<typeof ArkDrawer.Root>) => (
  <ArkDrawer.Root data-slot="drawer" {...props} />
);

export const DrawerTrigger = (
  props: React.ComponentProps<typeof ArkDrawer.Trigger>
) => <ArkDrawer.Trigger data-slot="drawer-trigger" {...props} />;

const drawerBackdropVariants = tv({
  base: [
    "fixed inset-0 z-40",
    "bg-black/32 backdrop-blur-sm",
    "data-[state=open]:fade-in-0 data-[state=open]:animate-in",
    "data-[state=closed]:fade-out-0 data-[state=closed]:animate-out",
  ],
});

export const DrawerBackdrop = (
  props: React.ComponentProps<typeof ArkDrawer.Backdrop>
) => {
  const { className, ...rest } = props;
  return (
    <ArkDrawer.Backdrop
      className={cn(drawerBackdropVariants(), className)}
      data-slot="drawer-backdrop"
      {...rest}
    />
  );
};

const drawerPositionerVariants = tv({
  base: ["fixed inset-0 z-50 grid"],
  variants: {
    side: {
      down: "grid grid-rows-[1fr_auto] pt-12",
      up: "grid grid-rows-[auto_1fr] pb-12",
      left: "flex justify-start",
      right: "flex justify-end",
    },
    variant: {
      default: "",
      inset: "sm:p-4",
    },
  },
  defaultVariants: {
    variant: "default",
  },
});

interface DrawerPositionerProps
  extends React.ComponentProps<typeof ArkDrawer.Positioner>,
    VariantProps<typeof drawerPositionerVariants> {}

export const DrawerPositioner = (props: DrawerPositionerProps) => {
  const { variant = "default", side = "down", className, ...rest } = props;

  return (
    <ArkDrawer.Positioner
      className={cn(drawerPositionerVariants({ side, variant }), className)}
      data-slot="drawer-positioner"
      {...rest}
    />
  );
};

const drawerContentVariants = tv({
  base: [
    "[--space:--spacing(6)]",
    "relative flex flex-col",
    "max-h-full min-h-0 w-full min-w-0",
    "bg-popover",
    "text-popover-foreground",
    "shadow-lg/5",
    "duration-200 ease-in-out will-change-transform",
    "data-[state=closed]:fade-out-0 data-[state=closed]:animate-out",
    "data-[state=open]:fade-in-0 data-[state=open]:animate-in",
  ],
  variants: {
    side: {
      down: [
        "row-start-2 border-t",
        "rounded-t-2xl",
      ],
      up: [
        "border-b",
        "rounded-b-2xl",
      ],
      left: [
        "h-full w-[calc(100%-(--spacing(12)))] max-w-md",
        "border-e",
        "rounded-e-2xl",
      ],
      right: [
        "h-full w-[calc(100%-(--spacing(12)))] max-w-md",
        "border-s",
        "rounded-s-2xl",
      ],
    },
    variant: {
      default: "",
      inset: [
        "sm:rounded-2xl sm:border",
        "sm:**:data-[slot=drawer-footer]:rounded-b-[calc(var(--radius-2xl)-1px)]",
      ],
    },
  },
  defaultVariants: {
    side: "down",
    variant: "default",
  },
});

interface DrawerContentProps
  extends React.ComponentProps<typeof ArkDrawer.Content>,
    VariantProps<typeof drawerContentVariants> {
  /**
   * Show close button at the top right corner
   *
   * @default true
   */
  showCloseButton?: boolean;
  /**
   * Show grabber handle for swipe gestures
   *
   * @default true
   */
  showGrabber?: boolean;
}

export const DrawerContent = (props: DrawerContentProps) => {
  const {
    showCloseButton = true,
    showGrabber = true,
    side = "down",
    variant = "default",
    className,
    children,
    ...rest
  } = props;

  return (
    <Portal>
      <DrawerBackdrop />

      <DrawerPositioner side={side} variant={variant}>
        <ArkDrawer.Content
          className={cn(drawerContentVariants({ side, variant }), className)}
          data-slot="drawer-content"
          {...rest}
        >
          {showGrabber && (
            <ArkDrawer.Grabber
              className="flex shrink-0 cursor-grab touch-none justify-center border-b py-3 active:cursor-grabbing data-[slot=drawer-content]:border-border"
              data-slot="drawer-grabber"
            >
              <ArkDrawer.GrabberIndicator
                className="h-1 w-10 shrink-0 rounded-full bg-muted-foreground/32"
                data-slot="drawer-grabber-indicator"
              />
            </ArkDrawer.Grabber>
          )}

          {children}

          {showCloseButton && (
            <ArkDrawer.CloseTrigger asChild>
              <Button
                aria-label="Close"
                className={cn(
                  "absolute inset-e-2 opacity-64 hover:opacity-100",
                  showGrabber ? "top-14" : "top-2"
                )}
                size="icon-md"
                variant="ghost"
              >
                <XIcon />
              </Button>
            </ArkDrawer.CloseTrigger>
          )}
        </ArkDrawer.Content>
      </DrawerPositioner>
    </Portal>
  );
};

interface DrawerHeaderProps extends React.ComponentProps<typeof ark.div> {
  /**
   * The description of the drawer
   */
  description?: string;
  /**
   * The title of the drawer
   */
  title?: string;
}

export const DrawerHeader = (props: DrawerHeaderProps) => {
  const { className, title, description, children, ...rest } = props;

  return (
    <ark.div
      className={cn(
        "flex flex-col gap-2 p-(--space) in-[[data-slot=drawer-content]:has([data-slot=drawer-body])]:pb-3",
        className
      )}
      data-slot="drawer-header"
      {...rest}
    >
      {!!title && <DrawerTitle>{title}</DrawerTitle>}

      {!!description && <DrawerDescription>{description}</DrawerDescription>}

      {!title && typeof children === "string" ? (
        <DrawerTitle>{children}</DrawerTitle>
      ) : (
        children
      )}
    </ark.div>
  );
};

export const DrawerTitle = (
  props: React.ComponentProps<typeof ArkDrawer.Title>
) => {
  const { className, ...rest } = props;
  return (
    <ArkDrawer.Title
      className={cn("font-semibold text-lg leading-none", className)}
      data-slot="drawer-title"
      {...rest}
    />
  );
};

export const DrawerDescription = (
  props: React.ComponentProps<typeof ark.div>
) => {
  const { className, ...rest } = props;
  return (
    <ark.div
      className={cn("text-muted-foreground text-sm", className)}
      data-slot="drawer-description"
      {...rest}
    />
  );
};

interface DrawerBodyProps extends React.ComponentProps<typeof ark.div> {
  /**
   * Add a fade effect to the scroll area
   *
   * @default false
   */
  scrollFade?: boolean;
}

export const DrawerBody = (props: DrawerBodyProps) => {
  const { scrollFade = false, className, ...rest } = props;

  return (
    <ScrollArea scrollFade={scrollFade}>
      <ark.div
        className={cn(
          "flex-1",
          "p-(--space)",
          "overflow-auto",
          "in-[[data-slot=drawer-content]:has([data-slot=drawer-header])]:pt-0",
          "in-[[data-slot=drawer-content]:has([data-slot=drawer-footer]:not(.border-t))]:pb-1",
          className
        )}
        data-slot="drawer-body"
        {...rest}
      />
    </ScrollArea>
  );
};

export const DrawerClose = (
  props: React.ComponentProps<typeof ArkDrawer.CloseTrigger>
) => <ArkDrawer.CloseTrigger data-slot="drawer-close" {...props} />;

export const DrawerFooter = (props: React.ComponentProps<typeof ark.div>) => {
  const { className, ...rest } = props;

  return (
    <ark.div
      className={cn(
        "flex flex-col-reverse gap-2 sm:flex-row sm:justify-end",
        "sm:rounded-none",
        "px-(--space) py-4",
        "bg-muted/72",
        "border-t",
        className
      )}
      data-slot="drawer-footer"
      {...rest}
    />
  );
};
